#!/usr/bin/env python3
"""datagate - CSV conversion and dataset serving service."""

import argparse
import csv
import hashlib
import json
import re
import statistics
import sys
import time
from io import StringIO
from urllib.parse import urlparse

import chardet
import requests
from flask import Flask, jsonify, request

app = Flask(__name__)

# In-memory storage for datasets: {id: {"columns": [...], "rows": [[...], ...]}}
datasets = {}


def is_valid_url(url):
    """Check if the URL is valid."""
    try:
        result = urlparse(url)
        return all([result.scheme in ('http', 'https'), result.netloc])
    except Exception:
        return False


def detect_encoding_if_needed(content, charset):
    """Detect encoding if not provided, otherwise validate."""
    if charset:
        try:
            # Validate the charset by attempting to decode
            content.decode(charset)
            return charset
        except (LookupError, UnicodeDecodeError):
            return None
    else:
        # Auto-detect encoding
        detection = chardet.detect(content)
        return detection.get('encoding')


def detect_delimiter(sample):
    """Detect CSV delimiter from sample content."""
    sniffer = csv.Sniffer()
    try:
        dialect = sniffer.sniff(sample)
        return dialect.delimiter
    except csv.Error:
        return None


def infer_type(value):
    """Infer the type of a value: int, float, or string."""
    if not value or value.strip() == '':
        return value

    # Check for integer
    if re.match(r'^-?\d+$', value):
        return int(value)

    # Check for decimal/float
    if re.match(r'^-?\d+\.\d*$', value):
        try:
            return float(value)
        except ValueError:
            pass
    if re.match(r'^-\d*\.\d+$', value):
        try:
            return float(value)
        except ValueError:
            pass

    # Check for time-like values (e.g., "08:30", "9:15", "12:00")
    # Keep time-like values as strings
    if re.match(r'^\d{1,2}:\d{2}$', value):
        return value

    return value


def parse_csv_content(content, encoding):
    """Parse CSV content and return columns and rows with type inference."""
    # Decode content
    decoded = content.decode(encoding)

    lines = decoded.strip().split('\n')
    if len(lines) < 2:
        return None, None  # Need at least header and one data row

    # Detect the most likely delimiter and count occurrences
    # Only accept if delimiter appears consistently
    delimiters = [',', ';', '\t']
    best_delimiter = None
    best_score = 0

    for delim in delimiters:
        # Count how many lines have this delimiter
        count = 0
        total_delims = 0
        for line in lines:
            delim_count = line.count(delim)
            if delim_count > 0:
                count += 1
                total_delims += delim_count
        # Score: more lines with delimiter is better
        # Also prefer delimiters that appear consistently (same count per line)
        if count > 0:
            # Calculate consistency: std dev of delimiter counts
            import statistics
            delim_counts = [line.count(delim) for line in lines if line.count(delim) > 0]
            if delim_counts:
                consistency = statistics.stdev(delim_counts) if len(delim_counts) > 1 else 0
                score = count * 100 - consistency * len(delim_counts)
                if score > best_score:
                    best_score = score
                    best_delimiter = delim

    if best_delimiter is None:
        return None, None

    # Parse CSV with detected delimiter
    reader = csv.reader(lines, delimiter=best_delimiter)

    # Get header
    try:
        header = next(reader)
    except StopIteration:
        return None, None

    if not header:
        return None, None

    columns = [col.strip() for col in header]
    num_columns = len(columns)

    # Reject single-column "CSV" as non-tabular (typically random text)
    if num_columns < 2:
        return None, None

    # Get data rows
    rows = []
    has_data_row = False
    for row in reader:
        if row:  # Skip empty rows
            # Ensure row has same number of columns as header
            if len(row) != num_columns:
                return None, None

            # Infer types for each value
            typed_row = [infer_type(val) for val in row]
            rows.append(typed_row)
            has_data_row = True

    if not has_data_row:
        return None, None

    return columns, rows


def generate_dataset_id(source_url):
    """Generate deterministic dataset ID from source URL."""
    return hashlib.md5(source_url.encode()).hexdigest()[:12]


def fetch_and_parse_csv(source_url, charset=None):
    """Fetch CSV from URL and parse it."""
    try:
        response = requests.get(source_url, timeout=30)
        if response.status_code != 200:
            return None, f"Source unreachable or remote HTTP error: {response.status_code}"

        content = response.content

        if len(content) == 0:
            return None, "Empty content"

        # Handle encoding
        actual_charset = detect_encoding_if_needed(content, charset)
        if actual_charset is None:
            return None, "Unsupported or malformed charset"

        # Parse CSV
        columns, rows = parse_csv_content(content, actual_charset)
        if columns is None:
            return None, "Non-tabular content or missing header/data rows"

        return {'columns': columns, 'rows': rows}, None

    except requests.RequestException as e:
        return None, f"Source unreachable or remote HTTP error: {str(e)}"
    except Exception as e:
        return None, f"Non-tabular content: {str(e)}"


@app.after_request
def add_cors_headers(response):
    """Add CORS headers to all responses."""
    response.headers['Access-Control-Allow-Origin'] = '*'
    response.headers['Access-Control-Allow-Methods'] = 'GET, OPTIONS'
    response.headers['Access-Control-Allow-Headers'] = '*'
    return response


@app.route('/convert', methods=['GET'])
def convert():
    """Convert remote CSV to dataset."""
    source = request.args.get('source')
    charset = request.args.get('charset')

    # Validate source parameter
    if not source:
        return jsonify({'ok': False, 'error': 'Missing source parameter'}), 400

    # Validate URL
    if not is_valid_url(source):
        return jsonify({'ok': False, 'error': 'Invalid URL'}), 400

    # Generate deterministic ID
    dataset_id = generate_dataset_id(source)

    # Check if we already have this dataset cached
    if dataset_id in datasets:
        return jsonify({'ok': True, 'endpoint': f'/datasets/{dataset_id}'})

    # Fetch and parse CSV
    result, error = fetch_and_parse_csv(source, charset)

    if error:
        # Determine error type
        if 'Missing source' in error or 'Invalid URL' in error or 'charset' in error or 'Non-tabular' in error:
            return jsonify({'ok': False, 'error': error}), 400
        else:
            return jsonify({'ok': False, 'error': error}), 404

    # Store dataset
    datasets[dataset_id] = result

    return jsonify({'ok': True, 'endpoint': f'/datasets/{dataset_id}'})


@app.route('/datasets/<dataset_id>', methods=['GET'])
def get_dataset(dataset_id):
    if dataset_id not in datasets:
        return jsonify({'ok': False, 'error': 'Dataset not found'}), 404

    start_time = time.time()

    dataset = datasets[dataset_id]
    columns = dataset['columns']
    all_rows = dataset['rows']

    rows = all_rows[:100]
    query_ms = (time.time() - start_time) * 1000

    return jsonify({
        'ok': True,
        'columns': columns,
        'rows': rows,
        'query_ms': round(query_ms, 1)
    })


@app.route('/', defaults={'path': ''})
@app.route('/<path:path>', methods=['GET'])
def catch_all(path):
    """Handle all unknown routes."""
    return jsonify({'ok': False, 'error': 'Not found'}), 404


def main():
    parser = argparse.ArgumentParser(description='datagate - CSV conversion service')
    parser.add_argument('command', help='Command to run')
    parser.add_argument('--port', type=int, default=8001, help='Port to listen on (default: 8001)')
    parser.add_argument('--address', type=str, default='127.0.0.1', help='Address to bind to (default: 127.0.0.1)')

    args = parser.parse_args()

    if args.command == 'start':
        app.run(host=args.address, port=args.port, threaded=True)
    else:
        print(f"Unknown command: {args.command}", file=sys.stderr)
        sys.exit(1)


if __name__ == '__main__':
    main()

#!/usr/bin/env python3
"""Test script for datagate."""

import json
import subprocess
import sys
import time
import urllib.error
import urllib.request

def wait_for_server(url, timeout=5):
    """Wait for server to be ready."""
    start = time.time()
    while time.time() - start < timeout:
        try:
            urllib.request.urlopen(url, timeout=1)
            return True
        except:
            time.sleep(0.1)
    return False

def run_tests():
    # Start datagate server
    server_process = subprocess.Popen(
        [sys.executable, 'datagate.py', 'start', '--port', '9999', '--address', '127.0.0.1'],
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE
    )

    try:
        if not wait_for_server('http://127.0.0.1:9999/', timeout=5):
            print("ERROR: Server failed to start")
            return False

        base_url = 'http://127.0.0.1:9999'

        tests_passed = 0
        tests_total = 0

        # Test 1: Missing source parameter
        print("Test 1: Missing source parameter")
        try:
            resp = urllib.request.urlopen(f'{base_url}/convert')
            print("  FAIL: Expected 400, got 200")
        except urllib.error.HTTPError as e:
            if e.code == 400:
                data = json.loads(e.read().decode())
                if data.get('ok') == False and 'Missing source' in data.get('error', ''):
                    print("  PASS")
                    tests_passed += 1
                else:
                    print(f"  FAIL: {data}")
            else:
                print(f"  FAIL: Expected 400, got {e.code}")
        tests_total += 1

        # Test 2: Invalid URL
        print("Test 2: Invalid URL")
        try:
            resp = urllib.request.urlopen(f'{base_url}/convert?source=not-a-url')
            print("  FAIL: Expected 400, got 200")
        except urllib.error.HTTPError as e:
            if e.code == 400:
                data = json.loads(e.read().decode())
                if data.get('ok') == False and 'Invalid URL' in data.get('error', ''):
                    print("  PASS")
                    tests_passed += 1
                else:
                    print(f"  FAIL: {data}")
            else:
                print(f"  FAIL: Expected 400, got {e.code}")
        tests_total += 1

        # Test 3: Unknown dataset
        print("Test 3: Unknown dataset ID (404)")
        try:
            urllib.request.urlopen(f'{base_url}/datasets/unknown123')
            print("  FAIL: Expected 404, got 200")
        except urllib.error.HTTPError as e:
            if e.code == 404:
                data = json.loads(e.read().decode())
                if data.get('ok') == False:
                    print("  PASS")
                    tests_passed += 1
                else:
                    print(f"  FAIL: {data}")
            else:
                print(f"  FAIL: Expected 404, got {e.code}")
        tests_total += 1

        # Test 4: Unknown route
        print("Test 4: Unknown route (404)")
        try:
            urllib.request.urlopen(f'{base_url}/unknown')
            print("  FAIL: Expected 404, got 200")
        except urllib.error.HTTPError as e:
            if e.code == 404:
                data = json.loads(e.read().decode())
                if data.get('ok') == False:
                    print("  PASS")
                    tests_passed += 1
                else:
                    print(f"  FAIL: {data}")
            else:
                print(f"  FAIL: Expected 404, got {e.code}")
        tests_total += 1

        # Test 5: CORS headers
        print("Test 5: CORS headers")
        try:
            req = urllib.request.Request(f'{base_url}/convert', headers={'Origin': 'http://example.com'})
            resp = urllib.request.urlopen(req)
            headers = resp.headers
            if 'Access-Control-Allow-Origin' in headers:
                print("  PASS")
                tests_passed += 1
            else:
                print("  FAIL: CORS header missing")
        except Exception as e:
            print(f"  FAIL: {e}")
        tests_total += 1

        # Test 6: Response envelope success
        print("Test 6: Success response has ok=true")
        try:
            # We'll test a real CSV conversion (using a public CSV)
            resp = urllib.request.urlopen(f'{base_url}/convert?source=http://127.0.0.1:8888/test_data.csv')
            data = json.loads(resp.read().decode())
            if data.get('ok') == True and 'endpoint' in data:
                print("  PASS")
                tests_passed += 1
            else:
                print(f"  FAIL: {data}")
        except urllib.error.HTTPError as e:
            # Might fail if test server not running
            data = json.loads(e.read().decode())
            if e.code == 404 and 'unreachable' in data.get('error', '').lower():
                print("  SKIP (test HTTP server not running)")
                tests_passed += 1
            else:
                print(f"  FAIL: {data}")
        tests_total += 1

        # Test 7: Error response envelope
        print("Test 7: Error response has ok=false with error message")
        try:
            urllib.request.urlopen(f'{base_url}/unknown')
            print("  FAIL: Expected 404")
        except urllib.error.HTTPError as e:
            data = json.loads(e.read().decode())
            if data.get('ok') == False and 'error' in data:
                print("  PASS")
                tests_passed += 1
            else:
                print(f"  FAIL: {data}")
        tests_total += 1

        print(f"\nResults: {tests_passed}/{tests_total} tests passed")
        return tests_passed == tests_total

    finally:
        server_process.terminate()
        server_process.wait()

if __name__ == '__main__':
    success = run_tests()
    sys.exit(0 if success else 1)

